import React, { useState } from "react";

const VRSTE = [
  { kod: "KP", naziv: "Kazneni predmet" },
  { kod: "UP", naziv: "Upravni predmet" },
  { kod: "PP", naziv: "Parični predmet" },
  { kod: "OS", naziv: "Obiteljski predmet" },
];

export default function NovPredmetModal({ onSave, onClose }) {
  const [form, setForm] = useState({
    vrsta: "KP",
    tuziteljIme: "", tuziteljOib: "",
    tuzeniIme:   "", tuzeniOib:   "",
    sud: "", sudac: "", opis: "",
  });
  const [loading, setLoading] = useState(false);
  const [error, setError]     = useState("");

  const set = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  const submit = async () => {
    if (!form.tuziteljIme.trim() || !form.tuzeniIme.trim()) {
      setError("Tužitelj i tuženi su obavezni.");
      return;
    }
    setLoading(true);
    setError("");
    try {
      await onSave({
        vrsta:    form.vrsta,
        tuzitelj: { ime: form.tuziteljIme.trim(), oib: form.tuziteljOib.trim() },
        tuzeni:   { ime: form.tuzeniIme.trim(),   oib: form.tuzeniOib.trim()   },
        sud:      form.sud,
        sudac:    form.sudac,
        opis:     form.opis,
      });
      onClose();
    } catch (e) {
      setError(e.message);
      setLoading(false);
    }
  };

  return (
    <div className="modal-overlay" onClick={(e) => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <div className="modal-header">
          <span className="modal-title">Novi predmet</span>
          <button className="btn-close" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          {error && <div style={{ color: "var(--red)", marginBottom: 16, fontSize: 13 }}>⚠ {error}</div>}
          <div className="form-grid">
            <div className="form-group">
              <label>Vrsta predmeta</label>
              <select value={form.vrsta} onChange={(e) => set("vrsta", e.target.value)}>
                {VRSTE.map((v) => <option key={v.kod} value={v.kod}>{v.kod} – {v.naziv}</option>)}
              </select>
            </div>
            <div className="form-group" style={{ justifyContent: "flex-end" }}>
              <label>Oznaka (automatski)</label>
              <input value={`${form.vrsta}XXXX/${String(new Date().getFullYear()).slice(-2)}`} disabled style={{ opacity: .5 }} />
            </div>

            <div className="form-group">
              <label>Tužitelj – ime i prezime / naziv *</label>
              <input
                placeholder="Ime i prezime ili naziv tvrtke"
                value={form.tuziteljIme}
                onChange={(e) => set("tuziteljIme", e.target.value)}
              />
            </div>
            <div className="form-group">
              <label>Tužitelj – OIB</label>
              <input
                placeholder="11 znamenki"
                maxLength={11}
                value={form.tuziteljOib}
                onChange={(e) => set("tuziteljOib", e.target.value.replace(/\D/g, ""))}
              />
            </div>

            <div className="form-group">
              <label>Tuženi – ime i prezime / naziv *</label>
              <input
                placeholder="Ime i prezime ili naziv tvrtke"
                value={form.tuzeniIme}
                onChange={(e) => set("tuzeniIme", e.target.value)}
              />
            </div>
            <div className="form-group">
              <label>Tuženi – OIB</label>
              <input
                placeholder="11 znamenki"
                maxLength={11}
                value={form.tuzeniOib}
                onChange={(e) => set("tuzeniOib", e.target.value.replace(/\D/g, ""))}
              />
            </div>

            <div className="form-group">
              <label>Sud</label>
              <input placeholder="npr. Općinski sud Zagreb" value={form.sud} onChange={(e) => set("sud", e.target.value)} />
            </div>
            <div className="form-group">
              <label>Sudac</label>
              <input placeholder="Ime i prezime suca" value={form.sudac} onChange={(e) => set("sudac", e.target.value)} />
            </div>
            <div className="form-group full">
              <label>Kratak opis predmeta</label>
              <textarea placeholder="Ukratko opisite predmet..." value={form.opis} onChange={(e) => set("opis", e.target.value)} />
            </div>
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn btn-ghost" onClick={onClose}>Odustani</button>
          <button className="btn btn-primary" onClick={submit} disabled={loading}>
            {loading ? "Spremam..." : "Otvori predmet"}
          </button>
        </div>
      </div>
    </div>
  );
}
